+  it("keeps provider card schema optional after merging into the message tool schema", () => {
+    const feishuPlugin = createChannelPlugin({
+      id: "feishu",
+      label: "Feishu",
+      docsPath: "/channels/feishu",
+      blurb: "Feishu test plugin.",
+      actions: ["send"],
